            yield return "        {";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "            return 0x"), Hash), ";"))
            {
                yield return _Line;
            }
            yield return "        }";
            yield return "    }";
            yield return "";
            yield return "    public IDataAccess Create(String ConnectionString)";
            yield return "    {";
            yield return "        return new MySqlDataAccess(ConnectionString, IsolationLevel.ReadCommitted, (ITransactionLock)(null));";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, IsolationLevel IsolationLevel)";
            yield return "    {";
            yield return "        return new MySqlDataAccess(ConnectionString, IsolationLevel, (ITransactionLock)(null));";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, ITransactionLock TransactionLock)";
            yield return "    {";
            yield return "        return new MySqlDataAccess(ConnectionString, IsolationLevel.ReadCommitted, TransactionLock);";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, IsolationLevel IsolationLevel, ITransactionLock TransactionLock)";
            yield return "    {";
            yield return "        return new MySqlDataAccess(ConnectionString, IsolationLevel, TransactionLock);";
            yield return "    }";
            yield return "    public IDataAccess Create(String ConnectionString, IsolationLevel IsolationLevel, Func<MySqlConnection, MySqlTransaction, ITransactionLock> TransactionLockFactory)";
            yield return "    {";
            yield return "        return new MySqlDataAccess(ConnectionString, IsolationLevel, TransactionLockFactory);";
            yield return "    }";
            yield return "}";
        }
        public IEnumerable<String> Main(String NamespaceName, IEnumerable<String> Imports, IEnumerable<String> Primitives, IEnumerable<String> ComplexTypes, Boolean EnableNullableDeclaration)
        {
            yield return "//==========================================================================";
            yield return "//";
            yield return "//  Notice:      This file is automatically generated.";
            yield return "//               Please don't modify this file.";
            yield return "//";
            yield return "//==========================================================================";
            yield return "";
            if (EnableNullableDeclaration)
            {
                yield return "#nullable disable";
                yield return "";
            }
            yield return "//Reference:";
            yield return "";
            yield return "using System;";
            yield return "using System.Collections.Generic;";
            yield return "using System.Diagnostics;";
            yield return "using System.Data;";
            yield return "using MySql.Data.MySqlClient;";
            if (EntityNamespaceName != NamespaceName && EntityNamespaceName != "")
            {
                foreach (var _Line in Combine(Combine(Combine(Begin(), "using "), EntityNamespaceName), ";"))
                {
                    yield return _Line;
                }
            }
            foreach (var _Line in Combine(Combine(Combine(Begin(), "using "), Imports), ";"))
            {
                yield return _Line;
            }
            foreach (var _Line in Combine(Begin(), Primitives))
            {
                yield return _Line;
            }
            yield return "";
            if (NamespaceName == "")
            {
                foreach (var _Line in Combine(Begin(), ComplexTypes))
                {
                    yield return _Line;
                }
            }
            else
            {
                foreach (var _Line in Combine(Combine(Begin(), "namespace "), GetEscapedIdentifier(NamespaceName)))
                {
                    yield return _Line;
                }
                yield return "{";
                foreach (var _Line in Combine(Combine(Begin(), "    "), ComplexTypes))
                {
                    yield return _Line;
                }
                yield return "}";
            }
            yield return "";
        }
    }
